<?php $tituloPagina="Primeiro Contato"; require_once "includes/header.php"; $pdo=getDB(); if($_SERVER["REQUEST_METHOD"]==="POST"){$a=$_POST["acao"]??"";if($a==="novo")$pdo->prepare("INSERT INTO primeiro_contato(empresa,talento_nome,talento_idade,resp_nome,telefone,telefone2,pais,estado,cidade,telemarketing_id,scouter_id,situacao,situacao2,observacoes,data_atendimento)VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)")->execute([$_POST["empresa"],$_POST["talento_nome"],$_POST["talento_idade"]??null,$_POST["resp_nome"]??"",$_POST["telefone"]??"",$_POST["telefone2"]??"",$_POST["pais"]??"BRASIL",$_POST["estado"]??"",$_POST["cidade"]??"",$_POST["telemarketing_id"]??null,$_POST["scouter_id"]??null,$_POST["situacao"]??"ABORDAGEM REALIZADA",$_POST["situacao2"]??"",$_POST["observacoes"]??"",$_POST["data_atendimento"]??null]);elseif($a==="editar")$pdo->prepare("UPDATE primeiro_contato SET empresa=?,talento_nome=?,talento_idade=?,resp_nome=?,telefone=?,telefone2=?,pais=?,estado=?,cidade=?,telemarketing_id=?,scouter_id=?,situacao=?,situacao2=?,observacoes=?,data_atendimento=? WHERE id=?")->execute([$_POST["empresa"],$_POST["talento_nome"],$_POST["talento_idade"]??null,$_POST["resp_nome"]??"",$_POST["telefone"]??"",$_POST["telefone2"]??"",$_POST["pais"]??"BRASIL",$_POST["estado"]??"",$_POST["cidade"]??"",$_POST["telemarketing_id"]??null,$_POST["scouter_id"]??null,$_POST["situacao"]??"ABORDAGEM REALIZADA",$_POST["situacao2"]??"",$_POST["observacoes"]??"",$_POST["data_atendimento"]??null,(int)$_POST["id"]]);elseif($a==="excluir")$pdo->prepare("DELETE FROM primeiro_contato WHERE id=?")->execute([(int)$_POST["id"]]);header("Location:/contatos.php");exit;} $tms=$pdo->query("SELECT id,nome,codigo FROM telemarketings WHERE situacao='ATIVO' ORDER BY nome")->fetchAll();$scs=$pdo->query("SELECT id,nome FROM scouters WHERE situacao='ATIVO' ORDER BY nome")->fetchAll();$total=(int)$pdo->query("SELECT COUNT(*) FROM primeiro_contato")->fetchColumn();$rows=$pdo->query("SELECT pc.*,t.nome AS tm_nome,s.nome 